-- Luke Chapter 23
-- Theme: The Trial before Pilate and Herod, Crucifixion, Death, and Burial of Jesus
-- 56 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 23,
  'Luke 23 narrates the most theologically dense day in human history: the trial, crucifixion, death, and burial of Jesus of Nazareth. The chapter opens with the entire Sanhedrin assembly (hapan to plēthos autōn, v.1) delivering Jesus to Pontius Pilate with three political charges carefully crafted to demand Roman attention: perverting the nation, forbidding tribute to Caesar, and claiming to be a king (v.2). Pilate''s threefold declaration of Jesus'' innocence (vv.4, 14, 22) structures the trial narrative and establishes the judicial truth that the reader must hold alongside the unjust verdict: the one condemned is the innocent one. Luke alone records the transfer to Herod Antipas (vv.6-12), who treats Jesus as entertainment, mocks him in "gorgeous robes" (esthēta lampran), and returns him to Pilate — achieving nothing except a surprising reconciliation between the two rulers (v.12), united in their contempt for the accused.' ||
  'The crucifixion narrative (vv.26-49) is distinctively Lucan in its emphasis on Jesus'' compassion and the responses of those surrounding the cross. The address to the weeping daughters of Jerusalem (vv.28-31) turns their mourning outward: "weep not for me, but weep for yourselves, and for your children" — a prophetic warning of Jerusalem''s coming destruction. The prayer "Father, forgive them; for they know not what they do" (v.34) — unique to Luke, though absent from some manuscripts — encapsulates the theology of the entire Gospel: divine forgiveness extended to those committing the supreme human crime. The repentant criminal''s exchange with Jesus (vv.39-43) contains the promise "To day shalt thou be with me in paradise" (v.43), a statement of immediate post-mortem fellowship with Christ that is among the most pastorally significant utterances in Scripture.' ||
  'The death of Jesus (vv.44-49) is accompanied by three cosmic signs: three hours of darkness over the whole land (v.44), the rending of the Temple veil (v.45), and Jesus'' final cry: "Father, into thy hands I commend my spirit" (v.46) — a quotation of Psalm 31:5, transforming the psalm of a righteous sufferer into the death-cry of the righteous Son. The centurion''s confession, "Certainly this was a righteous man" (v.47) — Luke''s distinctively ethical formulation (dikaios, not "Son of God" as in Mark 15:39) — pronounces the verdict that the trial failed to reach. The burial by Joseph of Arimathaea (vv.50-56), a member of the very council that condemned Jesus, demonstrates that even within the Sanhedrin there were dissenters. The women who observe the burial (v.55) prepare the way for the resurrection discovery in chapter 24.',
  'The Trial before Pilate and Herod, Crucifixion, Death, and Burial of Jesus',
  'δίκαιος (dikaios)',
  'dikaios means righteous, just, innocent — one who conforms to the standard of right. The word pervades Luke 23 as the chapter''s theological verdict on the crucified Jesus. Pilate declares him innocent three times (vv.4, 14, 22). The centurion at the cross proclaims "Certainly this was a righteous man" (ontōs ho anthrōpos houtos dikaios ēn, v.47). Joseph of Arimathaea, who buries Jesus, is himself described as "a good man, and a just" (anēr agathos kai dikaios, v.50). The repeated emphasis on Jesus'' righteousness/innocence throughout the chapter establishes the foundational truth of the atonement: the one who dies is the dikaios, the righteous one, and his death is therefore not punishment for his own sins but substitutionary sacrifice for others. Isaiah 53:11 prophesied: "by his knowledge shall my righteous servant justify many."',
  '["Jesus Before Pilate: Three Charges, Three Acquittals (vv.1-5)","Jesus Before Herod: Mocked and Returned (vv.6-12)","Pilate''s Verdict, Barabbas Released, Jesus Delivered (vv.13-25)","The Way to Calvary: Simon and the Daughters of Jerusalem (vv.26-31)","The Crucifixion: Father, Forgive Them (vv.32-38)","The Two Criminals: Paradise Promised (vv.39-43)","The Death of Jesus: Darkness, Torn Veil, Final Cry (vv.44-49)","The Burial by Joseph of Arimathaea (vv.50-56)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And the whole multitude of them arose, and led him unto Pilate.', 'Καὶ ἀναστὰν ἅπαν τὸ πλῆθος αὐτῶν ἤγαγον αὐτὸν ἐπὶ τὸν Πιλᾶτον.', 'Kai anastan hapan to plēthos autōn ēgagon auton epi ton Pilaton.', '"The whole multitude of them" (hapan to plēthos autōn — the entire body of them, the full assembly) — the Sanhedrin acts corporately in delivering Jesus to the Roman governor. "Led him unto Pilate" (ēgagon auton epi ton Pilaton — they led him to Pilate; Pontius Pilate, Roman prefect of Judea from AD 26-36, whose primary residence was in Caesarea Maritima but who came to Jerusalem during festivals to maintain order). The transfer from Jewish to Roman jurisdiction is theologically necessary: the Sanhedrin lacked authority to execute capital punishment (John 18:31), so the religious verdict must be converted into political charges that Rome would recognize. The movement from Sanhedrin to Pilate fulfills Jesus'' prediction of being "delivered unto the Gentiles" (18:32).', NULL),
  (2, 'And they began to accuse him, saying, We found this fellow perverting the nation, and forbidding to give tribute to Caesar, saying that he himself is Christ a King.', 'ἤρξαντο δὲ κατηγορεῖν αὐτοῦ λέγοντες, Τοῦτον εὕραμεν διαστρέφοντα τὸ ἔθνος ἡμῶν καὶ κωλύοντα φόρους Καίσαρι διδόναι καὶ λέγοντα ἑαυτὸν Χριστὸν βασιλέα εἶναι.', 'ērxanto de katēgorein autou legontes, Touton heuramen diastrephonta to ethnos hēmōn kai kōluonta phorous Kaisari didonai kai legonta heauton Christon basilea einai.', 'Three carefully crafted political charges, all designed to alarm Rome: (1) "Perverting the nation" (diastrephonta to ethnos — turning the nation aside, subverting; a charge of sedition); (2) "Forbidding to give tribute to Caesar" (kōluonta phorous Kaisari didonai — prohibiting taxes to Caesar) — a direct lie, since Jesus explicitly taught "Render to Caesar the things which be Caesar''s" (20:25); (3) "Saying that he himself is Christ a King" (legonta heauton Christon basilea einai — claiming to be an anointed king) — the religious charge of messianic identity is repackaged as political insurrection. The charges transform a theological claim into a threat to Roman sovereignty. Only the third charge has any basis in Jesus'' actual teaching, and even that is deliberately misrepresented.', NULL),
  (3, 'And Pilate asked him, saying, Art thou the King of the Jews? And he answered him and said, Thou sayest it.', 'ὁ δὲ Πιλᾶτος ἠρώτησεν αὐτὸν λέγων, Σὺ εἶ ὁ βασιλεὺς τῶν Ἰουδαίων; ὁ δὲ ἀποκριθεὶς αὐτῷ ἔφη, Σὺ λέγεις.', 'ho de Pilatos ērōtēsen auton legōn, Su ei ho basileus tōn Ioudaiōn? ho de apokritheis autō ephē, Su legeis.', '"Art thou the King of the Jews?" (Su ei ho basileus tōn Ioudaiōn — You are the king of the Jews?) — Pilate goes directly to the politically dangerous charge: royal claim. The question appears in all four Gospels in identical form — one of the rare verbatim agreements. "Thou sayest it" (Su legeis — you say it, you are the one saying this) — the same form of affirmative-yet-distancing response as before the Sanhedrin (22:70). Jesus affirms the title but without the political-military content Pilate assumes. His kingship is real but not the kind Rome needs to fear (cf. John 18:36: "My kingdom is not of this world"). The response is neither denial nor provocation but a truth that transcends the categories of the question.', NULL),
  (4, 'Then said Pilate to the chief priests and to the people, I find no fault in this man.', 'ὁ δὲ Πιλᾶτος εἶπεν πρὸς τοὺς ἀρχιερεῖς καὶ τοὺς ὄχλους, Οὐδὲν εὑρίσκω αἴτιον ἐν τῷ ἀνθρώπῳ τούτῳ.', 'ho de Pilatos eipen pros tous archiereis kai tous ochlous, Ouden heuriskō aition en tō anthrōpō toutō.', '"I find no fault in this man" (Ouden heuriskō aition en tō anthrōpō toutō — I find no cause/guilt in this man; aition = cause, ground for accusation, legal basis) — the first of Pilate''s three declarations of innocence (vv.4, 14, 22). Despite Jesus'' affirmation of kingship, Pilate recognizes that this man poses no political threat. The judicial verdict is clear: not guilty. From this point forward, the narrative tracks the progressive corruption of justice as Pilate, having declared Jesus innocent, nevertheless proceeds toward condemning him. The Roman governor''s triple acquittal, combined with his ultimate capitulation, presents a devastating portrait of political cowardice overriding judicial integrity.', NULL),
  (5, 'And they were the more fierce, saying, He stirreth up the people, teaching throughout all Jewry, beginning from Galilee to this place.', 'οἱ δὲ ἐπίσχυον λέγοντες ὅτι Ἀνασείει τὸν λαὸν διδάσκων καθ'' ὅλης τῆς Ἰουδαίας, καὶ ἀρξάμενος ἀπὸ τῆς Γαλιλαίας ἕως ὧδε.', 'hoi de epischuon legontes hoti Anaseiei ton laon didaskōn kath'' holēs tēs Ioudaias, kai arxamenos apo tēs Galilaias heōs hōde.', '"They were the more fierce" (epischuon — they grew stronger, they pressed harder, they intensified their insistence; epischuō = to strengthen upon, to become more urgent). "He stirreth up the people" (Anaseiei ton laon — he is shaking up the people, inciting the people; anaseiō = to shake up, to disturb; the language of political agitation). "Teaching throughout all Jewry, beginning from Galilee to this place" — they expand the charge from a Jerusalem incident to a nationwide campaign of subversion. The mention of "Galilee" provides Pilate with a jurisdictional escape route (v.6): if Jesus is a Galilean, Herod Antipas — ruler of Galilee and present in Jerusalem for Passover — has potential jurisdiction.', NULL),
  (6, 'When Pilate heard of Galilee, he asked whether the man were a Galilaean.', 'Πιλᾶτος δὲ ἀκούσας ἐπηρώτησεν εἰ ὁ ἄνθρωπος Γαλιλαῖός ἐστιν·', 'Pilatos de akousas epērōtēsen ei ho anthrōpos Galilaios estin;', '"When Pilate heard of Galilee" (akousas — having heard; the mention of Galilee triggers a jurisdictional calculation) — Pilate seizes on the geographical detail. "Whether the man were a Galilaean" (ei ho anthrōpos Galilaios estin — if the man is a Galilean) — a judicial question about jurisdiction, not curiosity. This episode (vv.6-12) is unique to Luke and serves multiple narrative purposes: it provides another witness to Jesus'' innocence (Herod returns him without conviction), it fulfills the prophecy of appearing before "kings and rulers" (21:12), and it demonstrates the complicity of both Jewish and Gentile authorities in Jesus'' condemnation (cf. Acts 4:27: "both Herod, and Pontius Pilate, with the Gentiles, and the people of Israel, were gathered together").', NULL),
  (7, 'And as soon as he knew that he belonged unto Herod''s jurisdiction, he sent him to Herod, who himself also was at Jerusalem at that time.', 'καὶ ἐπιγνοὺς ὅτι ἐκ τῆς ἐξουσίας Ἡρῴδου ἐστὶν ἀνέπεμψεν αὐτὸν πρὸς Ἡρῴδην, ὄντα καὶ αὐτὸν ἐν Ἱεροσολύμοις ἐν ταύταις ταῖς ἡμέραις.', 'kai epignous hoti ek tēs exousias Hērōdou estin anepempsen auton pros Hērōdēn, onta kai auton en Hierosolumois en tautais tais hēmerais.', '"Herod''s jurisdiction" (ek tēs exousias Hērōdou — from the authority/domain of Herod; Herod Antipas, tetrarch of Galilee and Perea, son of Herod the Great, the same Herod who beheaded John the Baptist, 9:9). "Sent him to Herod" (anepempsen auton — sent him up/back; anapempō can mean to refer a case to a higher authority or to send back) — Pilate transfers the case, seeking to share or shift responsibility. "Was at Jerusalem at that time" (onta...en Hierosolumois en tautais tais hēmerais — being in Jerusalem in those days) — Herod was present for the Passover festival, staying perhaps in the Hasmonean Palace near the Temple. The transfer of Jesus from one ruler to another fulfills Psalm 2:2: "The kings of the earth set themselves...against the LORD, and against his anointed."', NULL),
  (8, 'And when Herod saw Jesus, he was exceeding glad: for he was desirous to see him of a long season, because he had heard many things of him; and he hoped to have seen some miracle done by him.', 'ὁ δὲ Ἡρῴδης ἰδὼν τὸν Ἰησοῦν ἐχάρη λίαν· ἦν γὰρ ἐξ ἱκανῶν χρόνων θέλων ἰδεῖν αὐτὸν διὰ τὸ ἀκούειν περὶ αὐτοῦ, καὶ ἤλπιζέν τι σημεῖον ἰδεῖν ὑπ'' αὐτοῦ γινόμενον.', 'ho de Hērōdēs idōn ton Iēsoun echarē lian; ēn gar ex hikanōn chronōn thelōn idein auton dia to akouein peri autou, kai ēlpizen ti sēmeion idein hup'' autou ginomenon.', '"Exceeding glad" (echarē lian — rejoiced greatly; the joy is superficial, born of curiosity rather than faith) — Herod''s gladness is the antithesis of genuine faith. "Desirous to see him of a long season" (ex hikanōn chronōn thelōn idein auton — for a considerable time wanting to see him) — Luke 9:9 recorded this desire: "Herod said...Who is this, of whom I hear such things? And he desired to see him." "Hoped to have seen some miracle" (ēlpizen ti sēmeion idein — was hoping to see some sign performed by him) — Herod treats Jesus as a performer, an entertainer, a wonder-worker to be summoned for a private show. This is the same attitude Jesus condemned when he said, "This is an evil generation: they seek a sign" (11:29). Jesus will not perform on demand for the curious.', NULL),
  (9, 'Then he questioned with him in many words; but he answered him nothing.', 'ἐπηρώτα δὲ αὐτὸν ἐν λόγοις ἱκανοῖς· αὐτὸς δὲ οὐδὲν ἀπεκρίνατο αὐτῷ.', 'epērōta de auton en logois hikanois; autos de ouden apekrinato autō.', '"Questioned with him in many words" (epērōta auton en logois hikanois — was questioning him with many words; the imperfect tense: kept questioning, at length) — Herod''s extended interrogation meets absolute silence. "He answered him nothing" (ouden apekrinato autō — he answered him nothing at all) — Jesus''s silence before Herod is complete and deliberate, in contrast to his responses (however guarded) before the Sanhedrin and Pilate. The silence fulfills Isaiah 53:7: "He was oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he openeth not his mouth." Herod''s curiosity does not deserve a response; he has already rejected the testimony of John the Baptist and is not asking in order to believe but to be entertained.', NULL),
  (10, 'And the chief priests and scribes stood and vehemently accused him.', 'εἱστήκεισαν δὲ οἱ ἀρχιερεῖς καὶ οἱ γραμματεῖς εὐτόνως κατηγοροῦντες αὐτοῦ.', 'heistēkeisan de hoi archiereis kai hoi grammateis eutonōs katēgorountes autou.', '"The chief priests and scribes stood" (heistēkeisan...hoi archiereis kai hoi grammateis — the chief priests and scribes had taken their stand; the pluperfect suggests they had positioned themselves and were maintaining their presence) — the accusers followed Jesus from Pilate to Herod, maintaining their prosecution across jurisdictions. "Vehemently accused him" (eutonōs katēgorountes autou — vigorously accusing him; eutonōs = with intensity, with stretched effort, forcefully; from eu/well + teinō/to stretch; the word suggests prosecutors straining every argument) — the volume and intensity of the accusation increases in proportion to Jesus'' silence. The more Jesus refuses to respond, the louder they shout.', NULL),
  (11, 'And Herod with his men of war set him at nought, and mocked him, and arrayed him in a gorgeous robe, and sent him again to Pilate.', 'ἐξουθενήσας δὲ αὐτὸν ὁ Ἡρῴδης σὺν τοῖς στρατεύμασιν αὐτοῦ καὶ ἐμπαίξας, περιβαλὼν ἐσθῆτα λαμπρὰν ἀνέπεμψεν αὐτὸν τῷ Πιλάτῳ.', 'exouthenēsas de auton ho Hērōdēs sun tois strateoumasin autou kai empaixas, peribalōn esthēta lampran anepempsen auton tō Pilatō.', '"Set him at nought" (exouthenēsas — treated with contempt, regarded as nothing; exoutheneō = to make nothing of, from ek + outhen/nothing) — the same word used for the Pharisee despising the tax collector (18:9). "Mocked him" (empaixas — having mocked, ridiculed). "Arrayed him in a gorgeous robe" (peribalōn esthēta lampran — having thrown around him a bright/splendid garment; lampros = shining, brilliant, splendid; possibly white or bright-colored, signifying royal pretension or perhaps innocence) — the robe is a cruel parody of royal clothing. "Sent him again to Pilate" (anepempsen auton tō Pilatō — sent him back to Pilate) — Herod refuses to convict, effectively adding a second acquittal to Pilate''s. Jesus is returned without a verdict, having been found guilty of nothing except being interesting enough to ridicule.', NULL),
  (12, 'And the same day Pilate and Herod were made friends together: for before they were at enmity between themselves.', 'ἐγένοντο δὲ φίλοι ὅ τε Ἡρῴδης καὶ ὁ Πιλᾶτος ἐν αὐτῇ τῇ ἡμέρᾳ μετ'' ἀλλήλων· προϋπῆρχον γὰρ ἐν ἔχθρᾳ ὄντες πρὸς αὐτούς.', 'egenonto de philoi ho te Hērōdēs kai ho Pilatos en autē tē hēmera met'' allēlōn; proupērchon gar en echthra ontes pros autous.', '"Pilate and Herod were made friends" (egenonto philoi — became friends; a grimly ironic note) — two rulers, previously hostile (perhaps due to the incident in 13:1 where Pilate killed Galileans, infringing on Herod''s subjects), find common ground in their shared treatment of Jesus. "For before they were at enmity" (proupērchon en echthra — they had previously been in enmity; echthra = hostility, hatred) — their reconciliation over Jesus'' body is a dark parody of the peace Christ brings. Acts 4:25-27 interprets this alliance through Psalm 2: "the kings of the earth stood up, and the rulers were gathered together against the Lord, and against his Christ. For of a truth against thy holy child Jesus, both Herod, and Pontius Pilate...were gathered together."', NULL),
  (13, 'And Pilate, when he had called together the chief priests and the rulers and the people,', 'Πιλᾶτος δὲ συγκαλεσάμενος τοὺς ἀρχιερεῖς καὶ τοὺς ἄρχοντας καὶ τὸν λαόν,', 'Pilatos de sunkalesamenos tous archiereis kai tous archontas kai ton laon,', '"Called together the chief priests and the rulers and the people" (sunkalesamenos tous archiereis kai tous archontas kai ton laon — having called together the chief priests, the rulers, and the people) — Pilate convenes a public assembly including not just the accusers but the general populace (ton laon). This is unique to Luke and creates the setting for the crowd''s demand for Barabbas. The inclusion of "the people" is significant because Luke has previously distinguished the people (who supported Jesus, 19:48; 21:38) from the leaders (who opposed him). The crowd''s eventual cry for crucifixion (v.21) therefore represents a tragic reversal of popular opinion, orchestrated by the leaders'' pressure.', NULL),
  (14, 'Said unto them, Ye have brought this man unto me, as one that perverteth the people: and, behold, I, having examined him before you, have found no fault in this man touching those things whereof ye accuse him:', 'εἶπεν πρὸς αὐτούς, Προσηνέγκατέ μοι τὸν ἄνθρωπον τοῦτον ὡς ἀποστρέφοντα τὸν λαόν, καὶ ἰδοὺ ἐγὼ ἐνώπιον ὑμῶν ἀνακρίνας οὐθὲν εὗρον ἐν τῷ ἀνθρώπῳ τούτῳ αἴτιον ὧν κατηγορεῖτε κατ'' αὐτοῦ·', 'eipen pros autous, Prosēnenkate moi ton anthrōpon touton hōs apostrephonta ton laon, kai idou egō enōpion humōn anakrinas outhen heuron en tō anthrōpō toutō aition hōn katēgoreite kat'' autou;', '"Having examined him before you" (enōpion humōn anakrinas — having examined him in your presence; anakrinō = to examine judicially, to conduct a legal investigation; a technical legal term for preliminary hearing) — Pilate''s examination was public, not private. "Have found no fault" (outhen heuron...aition — I found no cause/ground) — the second formal declaration of innocence. "Touching those things whereof ye accuse him" (hōn katēgoreite kat'' autou — concerning the things you charge against him) — Pilate specifically addresses the charges brought and finds every one of them groundless. The legal language is precise and formal: this is a judicial pronouncement of not guilty, made in public, addressing specific charges, after examination. The injustice of the eventual condemnation is thereby intensified.', NULL),
  (15, 'No, nor yet Herod: for I sent you to him; and, lo, nothing worthy of death is done unto him.', 'ἀλλ'' οὐδὲ Ἡρῴδης· ἀνέπεμψεν γὰρ αὐτὸν πρὸς ἡμᾶς· καὶ ἰδοὺ οὐδὲν ἄξιον θανάτου ἐστὶν πεπραγμένον αὐτῷ.', 'all'' oude Hērōdēs; anepempsen gar auton pros hēmas; kai idou ouden axion thanatou estin pepragmenon autō.', '"No, nor yet Herod" (all'' oude Hērōdēs — but not even Herod) — Pilate cites Herod''s failure to convict as corroborating evidence of innocence. "I sent you to him" — Pilate claims the referral was for independent examination. "Nothing worthy of death is done unto him" (ouden axion thanatou estin pepragmenon autō — nothing deserving of death has been done by him; axios thanatou = worthy of death, deserving capital punishment; the perfect passive pepragmenon indicates a thorough review of all alleged actions). Two jurisdictions — Roman and Herodian — have now examined Jesus and found him innocent of capital charges. The legal case against Jesus has collapsed, yet the narrative moves inexorably toward execution.', NULL),
  (16, 'I will therefore chastise him, and release him.', 'παιδεύσας οὖν αὐτὸν ἀπολύσω.', 'paideusas oun auton apolusō.', '"I will therefore chastise him" (paideusas auton — having disciplined him; paideuō = to educate, to discipline, to chastise; a lighter punishment than execution, involving beating or scourging) "and release him" (apolusō — I will release him). Pilate''s compromise is juridically corrupt: if Jesus is innocent, he should be released without punishment; if guilty, he should be convicted. To punish an innocent man as a concession to his accusers is itself an injustice. The proposal reveals Pilate''s character: he recognizes innocence but lacks the moral courage to uphold it against political pressure. This verse introduces the cycle of Pilate''s attempts to release Jesus and the crowd''s resistance, a cycle that will end in capitulation.', NULL),
  (17, '(For of necessity he must release one unto them at the feast.)', '(ἀνάγκην δὲ εἶχεν ἀπολύειν αὐτοῖς κατὰ ἑορτὴν ἕνα.)', '(anankēn de eichen apoluein autois kata heortēn hena.)', '"Of necessity he must release one" (anankēn eichen apoluein — he had a necessity to release; anankē = necessity, compulsion; the custom required releasing one prisoner during the festival) — this verse is absent from some important manuscripts and may be a scribal gloss from Mark 15:6 or Matthew 27:15. If original, it explains the Barabbas tradition: a Passover amnesty custom whereby the Roman governor released one prisoner as a gesture of goodwill. The irony is theologically rich: at the feast celebrating Israel''s liberation from Egypt, the people choose to liberate a murderer rather than their true Liberator.', NULL),
  (18, 'And they cried out all at once, saying, Away with this man, and release unto us Barabbas:', 'ἀνέκραγον δὲ παμπληθεὶ λέγοντες, Αἶρε τοῦτον, ἀπόλυσον δὲ ἡμῖν τὸν Βαραββᾶν·', 'anekragon de pamplēthei legontes, Aire touton, apoluson de hēmin ton Barabban;', '"They cried out all at once" (anekragon pamplēthei — they shouted out with the whole multitude; pamplēthei = the entire throng together, unanimously; anekragon from anakrazō = to scream, to cry out loudly) — the crowd acts in unified voice. "Away with this man" (Aire touton — take this one away, remove him; airō = to lift up, to take away, to remove) — a cry of rejection. "Release unto us Barabbas" (apoluson hēmin ton Barabban — release to us Barabbas) — Barabbas (Bar-Abbas = "son of the father") presents a name-level irony: the crowd chooses the "son of the father" who is a criminal over the true Son of the Father who is innocent. The substitution is a dark inversion of the gospel: the guilty one goes free while the innocent one goes to death.', NULL),
  (19, '(Who for a certain sedition made in the city, and for murder, was cast into prison.)', '(ὅστις ἦν διὰ στάσιν τινὰ γενομένην ἐν τῇ πόλει καὶ φόνον βληθεὶς ἐν τῇ φυλακῇ.)', '(hostis ēn dia stasin tina genomenēn en tē polei kai phonon blētheis en tē phulakē.)', '"For a certain sedition made in the city, and for murder" (dia stasin tina genomenēn en tē polei kai phonon — on account of a certain insurrection that had occurred in the city and murder; stasis = uprising, sedition, insurrection; phonos = murder, killing) — Luke is explicit: Barabbas is guilty of the very crimes of which Jesus was falsely accused. Jesus was charged with "perverting the nation" (v.2); Barabbas actually committed insurrection. Jesus was charged with political sedition; Barabbas is an actual seditionist and murderer. "Cast into prison" (blētheis en tē phulakē — having been thrown into prison) — Barabbas is a convicted criminal awaiting punishment. The exchange of the innocent for the guilty at the cross is prefigured in this very courtyard scene.', NULL),
  (20, 'Pilate therefore, willing to release Jesus, spake again to them.', 'πάλιν δὲ ὁ Πιλᾶτος προσεφώνησεν αὐτοῖς, θέλων ἀπολῦσαι τὸν Ἰησοῦν.', 'palin de ho Pilatos prosephōnēsen autois, thelōn apolusai ton Iēsoun.', '"Willing to release Jesus" (thelōn apolusai ton Iēsoun — wanting to release Jesus; thelō = to will, to desire, to intend) — Pilate''s will is to release Jesus; his capitulation is not from conviction of Jesus'' guilt but from political cowardice. "Spake again to them" (palin prosephōnēsen — again called out to them; prosephōneō = to address, to call out to) — Pilate attempts a second time to persuade the crowd toward release. The repetition of his attempts (vv.16, 20, 22) demonstrates both his recognition of Jesus'' innocence and his progressive failure to act on it. Each appeal represents a decreasing capacity to resist the crowd''s demand.', NULL),
  (21, 'But they cried, saying, Crucify him, crucify him.', 'οἱ δὲ ἐπεφώνουν λέγοντες, Σταύρωσον σταύρωσον αὐτόν.', 'hoi de epephōnoun legontes, Staurōson staurōson auton.', '"They cried" (epephōnoun — they kept shouting; the imperfect tense: ongoing, repeated shouting; epiphōneō = to shout upon, to acclaim or call out against). "Crucify him, crucify him" (Staurōson staurōson auton — crucify, crucify him; the doubled imperative expresses vehement insistence) — crucifixion was the most shameful and agonizing form of Roman execution, reserved for slaves, rebels, and the worst criminals. The word stauroō means to fix to a stake or cross. The crowd that days earlier welcomed Jesus into Jerusalem with "Hosanna" (19:38) now demands the most degrading death Rome could inflict. The repetition "crucify, crucify" reveals the frenzy of mob mentality overriding rational judgment.', NULL),
  (22, 'And he said unto them the third time, Why, what evil hath he done? I have found no cause of death in him: I will therefore chastise him, and let him go.', 'ὁ δὲ τρίτον εἶπεν πρὸς αὐτούς, Τί γὰρ κακὸν ἐποίησεν οὗτος; οὐδὲν αἴτιον θανάτου εὗρον ἐν αὐτῷ· παιδεύσας οὖν αὐτὸν ἀπολύσω.', 'ho de triton eipen pros autous, Ti gar kakon epoiēsen houtos? ouden aition thanatou heuron en autō; paideusas oun auton apolusō.', '"The third time" (triton — a third time; Luke explicitly numbers Pilate''s attempts, emphasizing his repeated acquittal). "Why, what evil hath he done?" (Ti gar kakon epoiēsen houtos — for what evil did this one do?) — Pilate demands evidence of actual wrongdoing. "I have found no cause of death in him" (ouden aition thanatou heuron en autō — I found no ground for a death sentence in him) — the third and final declaration of innocence. Three acquittals from the Roman governor, corroborated by Herod''s failure to convict, establish Jesus'' legal innocence with the weight of triple testimony (cf. Deut 19:15: "at the mouth of two or three witnesses"). Yet Pilate still offers the corrupt compromise: "chastise and release" — punishing an innocent man to appease an unjust mob.', NULL),
  (23, 'And they were instant with loud voices, requiring that he might be crucified. And the voices of them and of the chief priests prevailed.', 'οἱ δὲ ἐπέκειντο φωναῖς μεγάλαις αἰτούμενοι αὐτὸν σταυρωθῆναι, καὶ κατίσχυον αἱ φωναὶ αὐτῶν.', 'hoi de epekeinto phōnais megalais aitoumenoi auton staurōthēnai, kai katischuon hai phōnai autōn.', '"They were instant with loud voices" (epekeinto phōnais megalais — they pressed upon him with great voices; epikeimai = to press upon, to be urgent, to bear down on; the word conveys relentless, crushing pressure). "Requiring that he might be crucified" (aitoumenoi auton staurōthēnai — demanding that he be crucified). "The voices of them...prevailed" (katischuon hai phōnai autōn — their voices prevailed, overcame, overpowered; katischuō = to be strong against, to overpower) — volume replaces evidence; shouting replaces justice. The crowd''s noise literally overpowers Pilate''s judicial verdict. The verb katischuō appears in v.36''s prayer ("accounted worthy to escape") and in 21:36 — the same word for prevailing in prayer is used for the crowd''s prevailing demand for crucifixion.', NULL),
  (24, 'And Pilate gave sentence that it should be as they required.', 'καὶ Πιλᾶτος ἐπέκρινεν γενέσθαι τὸ αἴτημα αὐτῶν.', 'kai Pilatos epekrinen genesthai to aitēma autōn.', '"Pilate gave sentence" (Pilatos epekrinen — Pilate decided, gave judicial verdict; epikrinō = to adjudge, to give a decision; a legal term appearing only here in the NT) "that it should be as they required" (genesthai to aitēma autōn — that their request should be fulfilled). The verdict is rendered not by evidence but by pressure. Pilate abandons his threefold acquittal and grants the crowd''s demand. The juridical language (epekrinen) gives the capitulation a veneer of legality, but the reader knows the truth: an innocent man has been sentenced to death by a judge who declared him innocent three times. The sentence fulfills divine purpose (22:22) while exposing the full depth of human injustice.', NULL),
  (25, 'And he released unto them him that for sedition and murder was cast into prison, whom they had desired; but he delivered Jesus to their will.', 'ἀπέλυσεν δὲ τὸν διὰ στάσιν καὶ φόνον βεβλημένον εἰς φυλακὴν ὃν ᾐτοῦντο, τὸν δὲ Ἰησοῦν παρέδωκεν τῷ θελήματι αὐτῶν.', 'apelusen de ton dia stasin kai phonon beblēmenon eis phulakēn hon ētounto, ton de Iēsoun paredōken tō thelēmati autōn.', '"He released...him that for sedition and murder was cast into prison" — Luke repeats Barabbas''s crimes (cf. v.19) to drive home the injustice: the actually guilty seditionist and murderer goes free. "Whom they had desired" (hon ētounto — whom they had been requesting) — the crowd gets what it asked for. "Delivered Jesus to their will" (ton de Iēsoun paredōken tō thelēmati autōn — but Jesus he handed over to their will; paradidōmi = to hand over, to deliver up; the same word used for Judas''s betrayal and God''s providential delivery) — Pilate "hands over" Jesus, the language of betrayal. "To their will" (tō thelēmati autōn) — a bitter irony: in Gethsemane, Jesus surrendered to the Father''s will (22:42); now Pilate surrenders Jesus to the mob''s will. The two "wills" stand in stark contrast.', NULL),
  (26, 'And as they led him away, they laid hold upon one Simon, a Cyrenian, coming out of the country, and on him they laid the cross, that he might bear it after Jesus.', 'Καὶ ὡς ἀπήγαγον αὐτόν, ἐπιλαβόμενοι Σίμωνά τινα Κυρηναῖον ἐρχόμενον ἀπ'' ἀγροῦ ἐπέθηκαν αὐτῷ τὸν σταυρὸν φέρειν ὄπισθεν τοῦ Ἰησοῦ.', 'Kai hōs apēgagon auton, epilabomenoi Simōna tina Kurēnaion erchomenon ap'' agrou epethēkan autō ton stauron pherein opisthen tou Iēsou.', '"As they led him away" (hōs apēgagon auton — as they were leading him away) — the procession to Golgotha begins. "Simon, a Cyrenian" (Simōna tina Kurēnaion — a certain Simon of Cyrene; Cyrene was a major city in modern Libya with a significant Jewish population, cf. Acts 2:10; 6:9; 11:20; 13:1) — Mark 15:21 identifies him as "the father of Alexander and Rufus," suggesting he became known in the early church. "Coming out of the country" (erchomenon ap'' agrou — coming from the field/countryside). "They laid the cross" (epethēkan autō ton stauron — they placed upon him the cross; the patibulum, the horizontal crossbeam, typically carried by the condemned to the execution site). "That he might bear it after Jesus" (pherein opisthen tou Iēsou — to carry it behind Jesus) — the language echoes 14:27: "Whosoever doth not bear his cross, and come after me, cannot be my disciple." Simon involuntarily enacts the call to discipleship.', NULL),
  (27, 'And there followed him a great company of people, and of women, which also bewailed and lamented him.', 'Ἠκολούθει δὲ αὐτῷ πολὺ πλῆθος τοῦ λαοῦ καὶ γυναικῶν αἳ ἐκόπτοντο καὶ ἐθρήνουν αὐτόν.', 'Ēkolouthei de autō polu plēthos tou laou kai gunaikōn hai ekoptonto kai ethrēnoun auton.', '"A great company of people, and of women" (polu plēthos tou laou kai gunaikōn — a large multitude of the people and of women) — Luke distinguishes the women from the general crowd, highlighting their particular grief. "Bewailed and lamented him" (ekoptonto kai ethrēnoun auton — were beating their breasts and mourning for him; koptō = to cut, then to beat the breast in grief, a mourning gesture; thrēneō = to wail, to sing a dirge, to lament aloud) — these are not the same women who followed from Galilee (v.49) but Jerusalem women moved by compassion at the sight of Jesus'' suffering. Their public mourning is both a mark of genuine sympathy and a backdrop for Jesus'' prophetic response in the next verses.', NULL),
  (28, 'But Jesus turning unto them said, Daughters of Jerusalem, weep not for me, but weep for yourselves, and for your children.', 'στραφεὶς δὲ πρὸς αὐτὰς Ἰησοῦς εἶπεν, Θυγατέρες Ἰερουσαλήμ, μὴ κλαίετε ἐπ'' ἐμέ· πλὴν ἐφ'' ἑαυτὰς κλαίετε καὶ ἐπὶ τὰ τέκνα ὑμῶν·', 'strapheis de pros autas Iēsous eipen, Thugateres Ierousalēm, mē klaiete ep'' eme; plēn eph'' heautas klaiete kai epi ta tekna humōn;', '"Daughters of Jerusalem" (Thugateres Ierousalēm — daughters of Jerusalem; an OT poetic address, cf. Song of Sol 1:5; 2:7; 3:5) — Jesus, even on the way to execution, turns from his own suffering to prophetic concern for others. "Weep not for me, but weep for yourselves, and for your children" (mē klaiete ep'' eme; plēn eph'' heautas klaiete kai epi ta tekna humōn — do not weep over me; rather, weep over yourselves and over your children) — the command redirects their mourning from the present crucifixion to the coming catastrophe of AD 70. Jesus'' suffering, though terrible, is purposeful and redemptive; Jerusalem''s suffering will be judgment without remedy. The "children" of Jerusalem will experience the horrors of the siege Josephus describes: starvation, slaughter, and slavery.', NULL),
  (29, 'For, behold, the days are coming, in the which they shall say, Blessed are the barren, and the wombs that never bare, and the paps which never gave suck.', 'ὅτι ἰδοὺ ἔρχονται ἡμέραι ἐν αἷς ἐροῦσιν, Μακάριαι αἱ στεῖραι, καὶ αἱ κοιλίαι αἳ οὐκ ἐγέννησαν, καὶ μαστοὶ οἳ οὐκ ἔθρεψαν.', 'hoti idou erchontai hēmerai en hais erousin, Makariai hai steirai, kai hai koiliai hai ouk egennēsan, kai mastoi hoi ouk ethrepsan.', '"Blessed are the barren" (Makariai hai steirai — blessed/happy are the barren women) — in Jewish culture, where motherhood was the highest blessing and barrenness the greatest sorrow (cf. 1:25; Gen 30:1; 1 Sam 1:10-11), this beatitude is a terrifying inversion. The day will come when not having children is counted as a mercy, because children will face unspeakable suffering. "The wombs that never bare, and the paps which never gave suck" — the triad (barrenness, empty wombs, unused breasts) emphasizes that every aspect of motherhood will become a source of anguish rather than joy. This echoes the woe of 21:23: "woe unto them that are with child, and to them that give suck, in those days!" Josephus confirms the horrific fulfillment during the siege.', NULL),
  (30, 'Then shall they begin to say to the mountains, Fall on us; and to the hills, Cover us.', 'τότε ἄρξονται λέγειν τοῖς ὄρεσιν, Πέσετε ἐφ'' ἡμᾶς· καὶ τοῖς βουνοῖς, Καλύψατε ἡμᾶς·', 'tote arxontai legein tois oresin, Pesete eph'' hēmas; kai tois bounois, Kalupsate hēmas;', '"They shall begin to say to the mountains, Fall on us; and to the hills, Cover us" (tois oresin, Pesete eph'' hēmas; kai tois bounois, Kalupsate hēmas — to the mountains, Fall upon us; and to the hills, Cover us) — a direct quotation from Hosea 10:8, where the prophet describes the terror of divine judgment upon Samaria. The cry to be buried under mountains is the ultimate expression of despair: preferring death by crushing to facing the coming judgment. The imagery reappears in Revelation 6:16, where the same words are addressed to mountains by those fleeing the wrath of the Lamb. Jesus applies Hosea''s judgment oracle to Jerusalem: the city that kills its Messiah will experience the same annihilating judgment that fell on apostate Samaria.', NULL),
  (31, 'For if they do these things in a green tree, what shall be done in the dry?', 'ὅτι εἰ ἐν τῷ ὑγρῷ ξύλῳ ταῦτα ποιοῦσιν, ἐν τῷ ξηρῷ τί γένηται;', 'hoti ei en tō hugrō xulō tauta poiousin, en tō xērō ti genētai?', '"If they do these things in a green tree, what shall be done in the dry?" (ei en tō hugrō xulō tauta poiousin, en tō xērō ti genētai — if they do these things in the moist/green wood, what will happen in the dry?) — a proverbial saying comparing the present treatment of the "green tree" (Jesus, the innocent, fruitful one; cf. Ps 1:3; Ezek 20:47) with what will happen to the "dry tree" (Jerusalem, spiritually dead and ripe for burning; cf. Ezek 17:24; Isa 56:3). If Rome does this to an innocent man during peacetime, what will Rome do to a guilty, rebellious city during war? If the righteous Son of God suffers thus, what will the unrighteous suffer? The proverb operates on multiple levels and is one of Jesus'' most compressed and powerful sayings.', NULL),
  (32, 'And there were also two other, malefactors, led with him to be put to death.', 'Ἤγοντο δὲ καὶ ἕτεροι κακοῦργοι δύο σὺν αὐτῷ ἀναιρεθῆναι.', 'Ēgonto de kai heteroi kakourgoi duo sun autō anairethēnai.', '"Two other, malefactors" (heteroi kakourgoi duo — two other criminals; kakourgos from kakos/evil + ergon/work = evil-doer, criminal) — Luke uses kakourgos rather than Mark''s lēstai (bandits/insurrectionists). "Led with him" (sun autō — with him) — Jesus is grouped with criminals, fulfilling Isaiah 53:12 ("he was numbered with the transgressors," quoted by Jesus in 22:37). The grammatical construction "two other, malefactors" (heteroi kakourgoi duo) could be read as calling Jesus himself a malefactor ("two others, [also] criminals"), though the KJV punctuation avoids this implication. The juxtaposition is intentional: Jesus dies as he lived, among sinners (cf. 5:30; 7:34; 15:1-2), and the two criminals will provide the final dramatic tableau of human response to Christ: rejection and faith.', NULL),
  (33, 'And when they were come to the place, which is called Calvary, there they crucified him, and the malefactors, one on the right hand, and the other on the left.', 'Καὶ ὅτε ἦλθον ἐπὶ τὸν τόπον τὸν καλούμενον Κρανίον, ἐκεῖ ἐσταύρωσαν αὐτὸν καὶ τοὺς κακούργους, ὃν μὲν ἐκ δεξιῶν ὃν δὲ ἐξ ἀριστερῶν.', 'Kai hote ēlthon epi ton topon ton kaloumenon Kranion, ekei estaurōsan auton kai tous kakourgous, hon men ek dexiōn hon de ex aristerōn.', '"The place, which is called Calvary" (ton topon ton kaloumenon Kranion — the place called the Skull; Kranion is the Greek translation of the Aramaic Gulgalta/Golgotha; "Calvary" comes from the Latin Vulgate''s Calvaria) — the location was outside the city walls (Heb 13:12), likely a low rocky outcrop whose shape suggested a skull. "There they crucified him" (ekei estaurōsan auton — there they crucified him) — Luke narrates the crucifixion with remarkable restraint: no description of the nailing, the raising of the cross, or the physical agony. The verb alone (estaurōsan) carries the full horror. "One on the right hand, and the other on the left" (ek dexiōn...ex aristerōn — from the right...from the left) — the positioning fulfills the numbering with transgressors and creates the setting for the dramatic exchange of vv.39-43.', NULL),
  (34, 'Then said Jesus, Father, forgive them; for they know not what they do. And they parted his raiment, and cast lots.', 'ὁ δὲ Ἰησοῦς ἔλεγεν, Πάτερ, ἄφες αὐτοῖς· οὐ γὰρ οἴδασιν τί ποιοῦσιν. διαμεριζόμενοι δὲ τὰ ἱμάτια αὐτοῦ ἔβαλον κλήρους.', 'ho de Iēsous elegen, Pater, aphes autois; ou gar oidasin ti poiousin. diamerizomenoi de ta himatia autou ebalon klērous.', '"Father, forgive them; for they know not what they do" (Pater, aphes autois; ou gar oidasin ti poiousin — Father, forgive them, for they do not know what they are doing) — this prayer, unique to Luke, is absent from some early manuscripts (including P75 and Codex Vaticanus) but present in Sinaiticus and the majority tradition. If original — and the weight of evidence and Lucan theology favor originality — it is the supreme expression of the gospel: forgiveness offered at the moment of the greatest crime. "They know not what they do" (ou oidasin ti poiousin) — ignorance does not excuse the sin but provides grounds for mercy (cf. Acts 3:17: "through ignorance ye did it"). The imperfect tense (elegen — he kept saying) suggests Jesus prayed this repeatedly during the crucifixion. "They parted his raiment, and cast lots" — fulfilling Psalm 22:18.', NULL),
  (35, 'And the people stood beholding. And the rulers also with them derided him, saying, He saved others; let him save himself, if he be Christ, the chosen of God.', 'καὶ εἱστήκει ὁ λαὸς θεωρῶν. ἐξεμυκτήριζον δὲ καὶ οἱ ἄρχοντες λέγοντες, Ἄλλους ἔσωσεν, σωσάτω ἑαυτόν, εἰ οὗτός ἐστιν ὁ Χριστὸς τοῦ Θεοῦ ὁ ἐκλεκτός.', 'kai heistēkei ho laos theōrōn. exemuktērizon de kai hoi archontes legontes, Allous esōsen, sōsatō heauton, ei houtos estin ho Christos tou Theou ho eklektos.', '"The people stood beholding" (heistēkei ho laos theōrōn — the people had taken their stand, watching; theōreō = to observe, to be a spectator) — Luke distinguishes the people (who watch in silence) from the rulers (who mock actively). "The rulers...derided him" (exemuktērizon...hoi archontes — the rulers were sneering at him; ekmukterizō = to turn up the nose at, to mock with curled lip, from ek + muktēr/nostril = to snort at contemptuously). "He saved others; let him save himself" (Allous esōsen, sōsatō heauton — he saved others, let him save himself) — the taunt is unconsciously theological: it is precisely because he does not save himself that he is able to save others. The irony is that the mockery states the truth it cannot comprehend. "The chosen of God" (ho eklektos — the elect one; cf. Isa 42:1: "mine elect, in whom my soul delighteth").', NULL),
  (36, 'And the soldiers also mocked him, coming to him, and offering him vinegar,', 'ἐνέπαιξαν δὲ αὐτῷ καὶ οἱ στρατιῶται προσερχόμενοι, ὄξος προσφέροντες αὐτῷ', 'enepaixan de autō kai hoi stratiōtai proserchomenoi, oxos prospherontes autō', '"The soldiers also mocked him" (enepaixan...kai hoi stratiōtai — the soldiers also mocked; a second group of mockers after the rulers) — the mockery cascades from leaders to soldiers. "Offering him vinegar" (oxos prospherontes — offering sour wine/vinegar; oxos = sour wine, posca, the cheap wine diluted with water that was the standard military drink) — the offering may be a cruel joke (offering a condemned criminal a soldier''s drink) or a partial fulfillment of Psalm 69:21 ("in my thirst they gave me vinegar to drink"). The soldiers participate in the universal rejection of Jesus: rulers, soldiers, and one criminal (v.39) all mock, while only the common people watch in silence and the other criminal repents.', NULL),
  (37, 'And saying, If thou be the king of the Jews, save thyself.', 'καὶ λέγοντες, Εἰ σὺ εἶ ὁ βασιλεὺς τῶν Ἰουδαίων, σῶσον σεαυτόν.', 'kai legontes, Ei su ei ho basileus tōn Ioudaiōn, sōson seauton.', '"If thou be the king of the Jews, save thyself" (Ei su ei ho basileus tōn Ioudaiōn, sōson seauton — if you are the king of the Jews, save yourself) — the soldiers'' mockery parallels the rulers'' taunt (v.35) and the criminal''s challenge (v.39), creating a threefold "save yourself" pattern. Each uses the conditional "if" (ei) — challenging Jesus to prove his identity through self-preservation. The dramatic irony is layered: Jesus is the King of the Jews, and precisely by not saving himself he accomplishes salvation. The soldiers'' mockery focuses on the political charge (king of the Jews) while the rulers'' mockery focused on the religious claim (Christ, the chosen of God).', NULL),
  (38, 'And a superscription also was written over him in letters of Greek, and Latin, and Hebrew, THIS IS THE KING OF THE JEWS.', 'ἦν δὲ καὶ ἐπιγραφὴ ἐπ'' αὐτῷ, Ὁ βασιλεὺς τῶν Ἰουδαίων οὗτος.', 'ēn de kai epigraphē ep'' autō, Ho basileus tōn Ioudaiōn houtos.', '"A superscription also was written over him" (epigraphē ep'' autō — an inscription upon him; the titulus, a placard hung around the condemned man''s neck during procession or affixed to the cross, stating the crime) — Roman custom required public declaration of the capital charge. "In letters of Greek, and Latin, and Hebrew" — some manuscripts include this trilingual detail (cf. John 19:20); it proclaims Jesus'' kingship in the three languages of the ancient world: Greek (culture), Latin (law/empire), and Hebrew (religion). "THIS IS THE KING OF THE JEWS" (Ho basileus tōn Ioudaiōn houtos — this is the king of the Jews) — intended as an insult to both Jesus and the Jewish people, it is in fact the truth. The irony is absolute: the Roman state publishes the gospel in three languages on the cross itself.', NULL),
  (39, 'And one of the malefactors which were hanged railed on him, saying, If thou be Christ, save thyself and us.', 'Εἷς δὲ τῶν κρεμασθέντων κακούργων ἐβλασφήμει αὐτὸν λέγων, Οὐχὶ σὺ εἶ ὁ Χριστός; σῶσον σεαυτὸν καὶ ἡμᾶς.', 'Heis de tōn kremasthentōn kakourgōn eblasphēmei auton legōn, Ouchi su ei ho Christos? sōson seauton kai hēmas.', '"One of the malefactors which were hanged" (Heis tōn kremasthentōn kakourgōn — one of the criminals who had been hanged/suspended; kremannumi = to hang, to suspend; the term "hanged" for crucifixion connects to Deut 21:23: "he that is hanged is accursed of God," cf. Gal 3:13). "Railed on him" (eblasphēmei — was blaspheming, reviling; the imperfect: kept railing). "If thou be Christ, save thyself and us" (Ouchi su ei ho Christos? sōson seauton kai hēmas — Are you not the Christ? Save yourself and us!) — the third "save yourself" challenge. This criminal, suffering the same execution, demands self-saving power. His taunt adds "and us" — even his mockery contains an implicit request for rescue, though framed as derision. He represents the response of unbelief in extremis.', NULL),
  (40, 'But the other answering rebuked him, saying, Dost not thou fear God, seeing thou art in the same condemnation?', 'ἀποκριθεὶς δὲ ὁ ἕτερος ἐπιτιμῶν αὐτῷ ἔφη, Οὐδὲ φοβῇ σὺ τὸν Θεόν, ὅτι ἐν τῷ αὐτῷ κρίματι εἶ;', 'apokritheis de ho heteros epitimōn autō ephē, Oude phobē su ton Theon, hoti en tō autō krimati ei?', '"The other answering rebuked him" (ho heteros epitimōn — the other one, rebuking; epitimaō = to rebuke, to censure, the same word used for rebuking demons and storms) — the second criminal silences the first with a rebuke that carries spiritual authority. "Dost not thou fear God?" (Oude phobē su ton Theon — Do you not even fear God?) — the fear of God, the beginning of wisdom (Prov 1:7), is the foundation of this criminal''s response. "Seeing thou art in the same condemnation" (hoti en tō autō krimati ei — since you are in the same sentence/judgment) — facing imminent death should produce reverence, not mockery. The reproof recognizes that mocking one who suffers unjustly while oneself suffering justly is a further compounding of guilt.', NULL),
  (41, 'And we indeed justly; for we receive the due reward of our deeds: but this man hath done nothing amiss.', 'καὶ ἡμεῖς μὲν δικαίως, ἄξια γὰρ ὧν ἐπράξαμεν ἀπολαμβάνομεν· οὗτος δὲ οὐδὲν ἄτοπον ἔπραξεν.', 'kai hēmeis men dikaiōs, axia gar hōn epraxamen apolambanomen; houtos de ouden atopon epraxen.', '"We indeed justly" (hēmeis men dikaiōs — we indeed justly/righteously; dikaiōs = justly, as justice requires) — a remarkable confession: the criminal acknowledges the justice of his own punishment. "For we receive the due reward of our deeds" (axia gar hōn epraxamen apolambanomen — for we are receiving worthy things for what we did; a full confession of guilt and acceptance of just punishment). "But this man hath done nothing amiss" (houtos de ouden atopon epraxen — but this one has done nothing out of place; atopos = out of place, improper, wrong; literally, not in the right place) — the criminal becomes a witness to Jesus'' innocence, adding his testimony to Pilate''s threefold acquittal. A condemned criminal recognizes what the religious leaders, Herod, and Pilate failed to act upon: Jesus is innocent.', NULL),
  (42, 'And he said unto Jesus, Lord, remember me when thou comest into thy kingdom.', 'καὶ ἔλεγεν, Ἰησοῦ, μνήσθητί μου ὅταν ἔλθῃς εἰς τὴν βασιλείαν σου.', 'kai elegen, Iēsou, mnēsthēti mou hotan elthēs eis tēn basileian sou.', '"Lord, remember me" (Iēsou, mnēsthēti mou — Jesus, remember me; some manuscripts read "Lord/Kurie" instead of "Jesus"; mnēsthēti is the aorist passive imperative of mimnēskomai = remember, recall, call to mind) — the request is staggering in context: a dying criminal asks a dying man to remember him in a kingdom. "When thou comest into thy kingdom" (hotan elthēs eis tēn basileian sou — whenever you come into your kingdom) — the criminal sees through the humiliation of the cross to the reality of Jesus'' kingship. While rulers mock, soldiers jeer, and the other criminal rails, this man perceives the truth of the superscription: Jesus is indeed a king with a kingdom. His faith is perhaps the most remarkable in the entire Gospel: no miracles seen, no teaching heard, only a crucified man — and he believes.', NULL),
  (43, 'And Jesus said unto him, Verily I say unto thee, To day shalt thou be with me in paradise.', 'καὶ εἶπεν αὐτῷ, Ἀμήν σοι λέγω, σήμερον μετ'' ἐμοῦ ἔσῃ ἐν τῷ παραδείσῳ.', 'kai eipen autō, Amēn soi legō, sēmeron met'' emou esē en tō paradeisō.', '"Verily I say unto thee" (Amēn soi legō — truly I say to you; the solemn affirmation formula used throughout the Gospel for authoritative pronouncements). "To day" (sēmeron — today, this very day) — the immediacy is emphatic; the criminal expected a future kingdom remembrance but receives a present-day promise. "Shalt thou be with me" (met'' emou esē — you will be with me; the promise is personal fellowship: not merely paradise but paradise with Jesus) — the essence of the promise is the personal presence of Christ. "In paradise" (en tō paradeisō — in the paradise; paradeisos from Old Persian pairidaeza = an enclosed garden/park; used in the LXX for the Garden of Eden, Gen 2:8; and in 2 Cor 12:4 and Rev 2:7 for the heavenly garden of God''s presence). The promise extends to a convicted criminal the fullness of salvation at the last possible moment — a supreme expression of grace.', NULL),
  (44, 'And it was about the sixth hour, and there was a darkness over all the earth until the ninth hour.', 'Καὶ ἦν ἤδη ὡσεὶ ὥρα ἕκτη καὶ σκότος ἐγένετο ἐφ'' ὅλην τὴν γῆν ἕως ὥρας ἐνάτης,', 'Kai ēn ēdē hōsei hōra hektē kai skotos egeneto eph'' holēn tēn gēn heōs hōras enatēs,', '"About the sixth hour" (hōsei hōra hektē — approximately noon, the sixth hour from sunrise) "until the ninth hour" (heōs hōras enatēs — until 3 PM) — three hours of supernatural darkness at the brightest time of day. "Darkness over all the earth" (skotos egeneto eph'' holēn tēn gēn — darkness came upon the whole land/earth; gē can mean either "land" [Judea] or "earth" [globally]) — the darkness is not an eclipse (impossible during Passover''s full moon). The phenomenon echoes the plague of darkness in Egypt (Exod 10:22), the darkness prophesied in Amos 8:9 ("I will cause the sun to go down at noon, and I will darken the earth in the clear day"), and Joel 2:31 ("the sun shall be turned into darkness"). Creation itself responds to the death of its Creator; the cosmic order convulses as the source of all light is extinguished.', NULL),
  (45, 'And the sun was darkened, and the veil of the temple was rent in the midst.', 'τοῦ ἡλίου ἐκλιπόντος, ἐσχίσθη δὲ τὸ καταπέτασμα τοῦ ναοῦ μέσον.', 'tou hēliou eklipontos, eschisthē de to katapetasma tou naou meson.', '"The sun was darkened" (tou hēliou eklipontos — the sun failing, ceasing; ekleipō = to fail, to give out; the same word family as "eclipse," though this is not a natural eclipse). "The veil of the temple was rent in the midst" (eschisthē to katapetasma tou naou meson — the curtain of the Temple was split in the middle; katapetasma = the great curtain, likely the inner veil separating the Holy Place from the Holy of Holies, Exod 26:33; schizō = to tear, to rend; meson = in the middle, from top to bottom) — Luke places the veil-rending before Jesus'' death (unlike Mark, who places it after), perhaps to interpret the death through its significance: Jesus'' death opens access to God''s presence. The massive curtain (Josephus describes it as 60 feet tall and 4 inches thick) splits apart, symbolizing that the barrier between God and humanity is permanently removed by Christ''s sacrifice.', NULL),
  (46, 'And when Jesus had cried with a loud voice, he said, Father, into thy hands I commend my spirit: and having said thus, he gave up the ghost.', 'καὶ φωνήσας φωνῇ μεγάλῃ ὁ Ἰησοῦς εἶπεν, Πάτερ, εἰς χεῖράς σου παρατίθεμαι τὸ πνεῦμά μου· τοῦτο δὲ εἰπὼν ἐξέπνευσεν.', 'kai phōnēsas phōnē megalē ho Iēsous eipen, Pater, eis cheiras sou paratithemai to pneuma mou; touto de eipōn exepneusen.', '"Cried with a loud voice" (phōnēsas phōnē megalē — having called out with a great voice) — the loud cry indicates remaining strength; Jesus does not slip away quietly but dies with a shout. "Father, into thy hands I commend my spirit" (Pater, eis cheiras sou paratithemai to pneuma mou — Father, into your hands I place my spirit; paratithemai = I entrust, I deposit for safekeeping, from para + tithēmi; the same word used for entrusting a deposit to a banker) — a quotation of Psalm 31:5, with the characteristic Lucan addition of "Father" (Pater). Jesus dies as he lived: in trusting relationship with the Father. Luke omits the cry of dereliction ("My God, my God, why hast thou forsaken me?" Mark 15:34) and instead presents a death of supreme trust and filial confidence. "Gave up the ghost" (exepneusen — he breathed out, expired; ekpneō = to breathe out for the last time).', NULL),
  (47, 'Now when the centurion saw what was done, he glorified God, saying, Certainly this was a righteous man.', 'ἰδὼν δὲ ὁ ἑκατοντάρχης τὸ γενόμενον ἐδόξασεν τὸν Θεὸν λέγων, Ὄντως ὁ ἄνθρωπος οὗτος δίκαιος ἦν.', 'idōn de ho hekatontarchēs to genomenon edoxasen ton Theon legōn, Ontōs ho anthrōpos houtos dikaios ēn.', '"The centurion" (ho hekatontarchēs — the commander of 100 soldiers; the Roman officer supervising the execution). "Saw what was done" (idōn to genomenon — having seen what had happened; the darkness, the manner of death, the prayer of forgiveness, the final cry of trust). "Glorified God" (edoxasen ton Theon — he glorified God; a distinctively Lucan response, cf. 5:25; 7:16; 13:13; 17:15; 18:43). "Certainly this was a righteous man" (Ontōs ho anthrōpos houtos dikaios ēn — truly this man was righteous/innocent; ontōs = really, certainly, in truth; dikaios = righteous, just, innocent) — Luke''s version differs from Mark''s "Son of God" (Mark 15:39), using the ethical-judicial term dikaios. This is the chapter''s culminating verdict: the Roman soldier, a Gentile executioner, pronounces the same word that defines Jesus throughout this chapter — dikaios, righteous, innocent, just.', NULL),
  (48, 'And all the people that came together to that sight, beholding the things which were done, smote their breasts, and returned.', 'καὶ πάντες οἱ συμπαραγενόμενοι ὄχλοι ἐπὶ τὴν θεωρίαν ταύτην, θεωρήσαντες τὰ γενόμενα, τύπτοντες τὰ στήθη αὐτῶν ὑπέστρεφον.', 'kai pantes hoi sumparagenomenoi ochloi epi tēn theōrian tautēn, theōrēsantes ta genomena, tuptontes ta stēthē autōn hupesttrephon.', '"All the people that came together to that sight" (pantes hoi sumparagenomenoi ochloi epi tēn theōrian tautēn — all the assembled crowds at this spectacle; theōria = a viewing, a spectacle, from theōreō/to watch) — the crowd who came to watch an execution. "Beholding the things which were done" (theōrēsantes ta genomena — having observed the events). "Smote their breasts" (tuptontes ta stēthē autōn — beating their chests; the gesture of mourning and self-reproach, cf. 18:13 where the tax collector "smote upon his breast") — the crowd, who earlier demanded crucifixion (v.21), now beats their breasts in anguish. "And returned" (hupesttrephon — were returning; the imperfect: a slow, silent procession of people departing in grief). The breast-beating may indicate remorse, or at least the dawning awareness that something terrible and unjust has occurred.', NULL),
  (49, 'And all his acquaintance, and the women that followed him from Galilee, stood afar off, beholding these things.', 'εἱστήκεισαν δὲ πάντες οἱ γνωστοὶ αὐτῷ ἀπὸ μακρόθεν, καὶ γυναῖκες αἱ συνακολουθοῦσαι αὐτῷ ἀπὸ τῆς Γαλιλαίας, ὁρῶσαι ταῦτα.', 'heistēkeisan de pantes hoi gnōstoi autō apo makrothen, kai gunaikes hai sunakolouthousai autō apo tēs Galilaias, hōrōsai tauta.', '"All his acquaintance" (pantes hoi gnōstoi autō — all those known to him, his acquaintances; gnōstos = known, familiar) — the male disciples are present but at a distance. "The women that followed him from Galilee" (gunaikes hai sunakolouthousai autō apo tēs Galilaias — the women who had been following with him from Galilee; sunakoloutheō = to follow together with, to accompany) — these women, who supported Jesus''s ministry (8:1-3), maintain their vigil while male disciples keep their distance. "Stood afar off, beholding these things" (heistēkeisan apo makrothen...hōrōsai tauta — had taken their stand from a distance...watching these things) — the women''s faithful watching positions them as eyewitnesses to both the death (v.49) and the burial (v.55), making them the essential link to the resurrection discovery (24:1-10).', NULL),
  (50, 'And, behold, there was a man named Joseph, a counsellor; and he was a good man, and a just:', 'Καὶ ἰδοὺ ἀνὴρ ὀνόματι Ἰωσὴφ βουλευτὴς ὑπάρχων, ἀνὴρ ἀγαθὸς καὶ δίκαιος—', 'Kai idou anēr onomati Iōsēph bouleutēs huparchōn, anēr agathos kai dikaios—', '"Behold" (idou — look! pay attention!) — Luke introduces Joseph with dramatic emphasis, as if presenting a surprising witness. "A counsellor" (bouleutēs — a member of the council/Sanhedrin; the same body that condemned Jesus) — the detail is stunning: a member of the very court that convicted Jesus now buries him with honor. "A good man, and a just" (anēr agathos kai dikaios — a man good and righteous) — the same word dikaios used for the centurion''s verdict on Jesus (v.47). Joseph shares the character of the one he will bury. In a chapter where the word "righteous" defines Jesus, Joseph is described with the same adjective, indicating his alignment with the innocent one he honors in death.', NULL),
  (51, '(The same had not consented to the counsel and deed of them;) he was of Arimathaea, a city of the Jews: who also himself waited for the kingdom of God.', '(οὗτος οὐκ ἦν συγκατατεθειμένος τῇ βουλῇ καὶ τῇ πράξει αὐτῶν) ἀπὸ Ἁριμαθαίας πόλεως τῶν Ἰουδαίων, ὃς προσεδέχετο τὴν βασιλείαν τοῦ Θεοῦ.', '(houtos ouk ēn sunkatatetheimenos tē boulē kai tē praxei autōn) apo Harimathaias poleōs tōn Ioudaiōn, hos prosedecheto tēn basileian tou Theou.', '"Had not consented to the counsel and deed of them" (ouk ēn sunkatatetheimenos tē boulē kai tē praxei autōn — had not been in agreement with the plan and action of them; sunkatatithemai = to put down together with, to consent jointly; the pluperfect indicates a prior, settled position of dissent) — Joseph dissented from the Sanhedrin''s decision, though Luke does not say whether he abstained, voted against, or was absent. "Of Arimathaea" (apo Harimathaias — from Arimathea; identified with Ramathaim-zophim, Samuel''s hometown in Ephraim, 1 Sam 1:1). "Waited for the kingdom of God" (prosedecheto tēn basileian tou Theou — was expectantly awaiting the kingdom of God; prosdechomai = to receive toward, to await with eager expectation) — the same posture as Simeon (2:25) and Anna (2:38), marking him as one of the faithful remnant who longed for God''s redemptive action.', NULL),
  (52, 'This man went unto Pilate, and begged the body of Jesus.', 'οὗτος προσελθὼν τῷ Πιλάτῳ ᾐτήσατο τὸ σῶμα τοῦ Ἰησοῦ,', 'houtos proselthōn tō Pilatō ētēsato to sōma tou Iēsou,', '"Went unto Pilate" (proselthōn tō Pilatō — having approached Pilate; a courageous act, since requesting the body of a condemned criminal associated the petitioner with the executed person) — Joseph risks his reputation and possibly his freedom. "Begged the body of Jesus" (ētēsato to sōma tou Iēsou — requested the body of Jesus; aiteō = to ask, to request; not begging in the sense of pleading but formally petitioning the governor). Roman practice sometimes allowed family members or friends to claim bodies for burial; otherwise, criminals'' bodies were left on the cross or thrown into common graves. Joseph''s petition ensures that Jesus receives an honorable burial, fulfilling Isaiah 53:9 ("he made his grave with the rich in his death").', NULL),
  (53, 'And he took it down, and wrapped it in linen, and laid it in a sepulchre that was hewn in stone, wherein never man before was laid.', 'καὶ καθελὼν ἐνετύλιξεν αὐτὸ σινδόνι, καὶ ἔθηκεν αὐτὸν ἐν μνήματι λαξευτῷ οὗ οὐκ ἦν οὐδεὶς οὔπω κείμενος.', 'kai kathelōn enetulixen auto sindoni, kai ethēken auton en mnēmati laxeutō hou ouk ēn oudeis oupō keimenos.', '"Took it down" (kathelōn — having taken it down; from the cross, a physical labor requiring lowering the body from the nails). "Wrapped it in linen" (enetulixen auto sindoni — he wrapped it in a linen cloth; sindōn = fine linen, a burial shroud; a costly material, indicating Joseph''s wealth and devotion). "Laid it in a sepulchre that was hewn in stone" (ethēken auton en mnēmati laxeutō — he placed him in a rock-hewn tomb; laxeutos = cut from rock, a tomb carved out of limestone) — Jerusalem''s tombs were typically caves or chambers cut into the soft limestone hillsides. "Wherein never man before was laid" (hou ouk ēn oudeis oupō keimenos — where no one had yet been placed) — the tomb''s virgin condition ensures the resurrection cannot be confused with the revival of another person and fulfills Isaiah 53:9 concerning his burial "with the rich."', NULL),
  (54, 'And that day was the preparation, and the sabbath drew on.', 'καὶ ἡμέρα ἦν Παρασκευῆς, καὶ σάββατον ἐπέφωσκεν.', 'kai hēmera ēn Paraskeuēs, kai sabbaton epephōsken.', '"That day was the preparation" (hēmera ēn Paraskeuēs — the day was the Preparation; Paraskeuē was the technical name for Friday, the day of preparation before the Sabbath, when all work had to be completed before sunset) — the time pressure is significant: burial must be accomplished before the Sabbath begins at sundown. "The sabbath drew on" (sabbaton epephōsken — the Sabbath was dawning; epiphōskō literally means "to begin to grow light," but in Jewish reckoning, days begin at sunset, so "dawning" here means the Sabbath was approaching, the evening light of the new day was beginning) — the urgency explains the hasty burial without full anointing (which the women will attempt in 24:1). The Sabbath intervenes between death and resurrection, creating the "great silence" of Holy Saturday.', NULL),
  (55, 'And the women also, which came with him from Galilee, followed after, and beheld the sepulchre, and how his body was laid.', 'Κατακολουθήσασαι δὲ αἱ γυναῖκες, αἵτινες ἦσαν συνεληλυθυῖαι ἐκ τῆς Γαλιλαίας αὐτῷ, ἐθεάσαντο τὸ μνημεῖον καὶ ὡς ἐτέθη τὸ σῶμα αὐτοῦ,', 'Katakolouthēsasai de hai gunaikes, haitines ēsan sunelēluthuiai ek tēs Galilaias autō, etheasanto to mnēmeion kai hōs etethē to sōma autou,', '"The women also, which came with him from Galilee" (hai gunaikes...sunelēluthuiai ek tēs Galilaias — the women who had come together with him from Galilee; the same women as v.49 and 8:1-3). "Followed after" (Katakolouthēsasai — having followed closely; katakoloutheō = to follow behind, to follow in the train of) — they follow Joseph to the tomb. "Beheld the sepulchre, and how his body was laid" (etheasanto to mnēmeion kai hōs etethē to sōma autou — they observed the tomb and how his body was placed; theaomai = to gaze upon, to observe carefully, more deliberate than a casual glance) — they take careful note of the location and the position of the body. This meticulous observation serves a crucial narrative purpose: these same women will return on Sunday morning (24:1) and will be able to confirm that the tomb they find empty is the same tomb in which they watched the body placed.', NULL),
  (56, 'And they returned, and prepared spices and ointments; and rested the sabbath day according to the commandment.', 'ὑποστρέψασαι δὲ ἡτοίμασαν ἀρώματα καὶ μύρα. Καὶ τὸ μὲν σάββατον ἡσύχασαν κατὰ τὴν ἐντολήν.', 'hupostrepsasai de hētoimasan arōmata kai mura. Kai to men sabbaton hēsuchasan kata tēn entolēn.', '"Returned, and prepared spices and ointments" (hētoimasan arōmata kai mura — they prepared aromatic spices and ointments; arōmata = sweet spices used in burial preparation; mura = myrrh-based ointments for anointing the body) — the women immediately begin burial preparations, working against the clock before Sabbath. "Rested the sabbath day according to the commandment" (to men sabbaton hēsuchasan kata tēn entolēn — on the Sabbath they rested according to the commandment; hēsuchazō = to be still, to rest; entolē = commandment, the fourth commandment of Exod 20:8-11). The verse is remarkably poignant: even in their grief and urgency to properly prepare Jesus'' body, the women observe the Sabbath rest. Their obedience frames the narrative pause between crucifixion and resurrection. The body lies in the tomb; the women rest; the world holds its breath. The Sabbath rest of the commandment becomes the Sabbath rest of Christ''s body in the grave.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 23;
